<?php
namespace Tests\Feature;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Tests\TestCase;class HuntSchemaTest extends TestCase{use RefreshDatabase;public function test_hunts_schema_engine_collation_and_restrict(){$table=DB::selectOne("SELECT ENGINE,TABLE_COLLATION FROM information_schema.TABLES WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME='hunts'");$this->assertSame('InnoDB',$table->ENGINE);$this->assertSame('utf8mb4_unicode_ci',$table->TABLE_COLLATION);$rules=DB::select("SELECT DELETE_RULE FROM information_schema.REFERENTIAL_CONSTRAINTS WHERE CONSTRAINT_SCHEMA=DATABASE() AND TABLE_NAME='hunts'");$this->assertCount(3,$rules);foreach($rules as $r)$this->assertSame('RESTRICT',$r->DELETE_RULE);}}
